import React, { useState, useCallback } from 'react';
import { createPortal } from 'react-dom';
import type { BankStatementDryRunRow } from '../../../../../services/kt/bankStatementImportModels';
import { extractBulkRefsFromDescription } from '../../../../../utils/extractBatchRefs';
import styles from './BatchRefConfigModal.module.css';

interface BatchRefConfigModalProps {
  row: BankStatementDryRunRow;
  /** Current selected batch ref from resolution (if any). */
  currentSelectedRef?: string;
  /** Current isBatchTransaction flag. */
  currentIsBatch?: boolean;
  /** Current batch confirm reason. */
  currentReason?: string;
  onSave: (selectedBatchRef: string | undefined, isBatchTransaction: boolean, reason: string) => void;
  onClose: () => void;
}

const BatchRefConfigModal: React.FC<BatchRefConfigModalProps> = ({
  row,
  currentSelectedRef,
  currentIsBatch,
  currentReason,
  onSave,
  onClose,
}) => {
  // Detect refs from description (fallback if BE didn't detect)
  const detectedRefs = row.detectedBatchRefs?.length
    ? row.detectedBatchRefs
    : extractBulkRefsFromDescription(row.description || '');

  const [selectedRef, setSelectedRef] = useState(currentSelectedRef || (detectedRefs.length > 0 ? detectedRefs[0] : ''));
  const [manualRef, setManualRef] = useState('');
  const [useManual, setUseManual] = useState(false);
  const [isBatch, setIsBatch] = useState(currentIsBatch ?? false);
  const [reason, setReason] = useState(currentReason || '');

  const effectiveRef = useManual ? manualRef.trim() : selectedRef;

  const handleSave = useCallback(() => {
    onSave(
      effectiveRef || undefined,
      isBatch,
      isBatch && effectiveRef && !row.hasBatchDetail ? reason : '',
    );
    onClose();
  }, [effectiveRef, isBatch, reason, row.hasBatchDetail, onSave, onClose]);

  return createPortal(
    <div className={styles.overlay} onClick={onClose}>
      <div className={styles.modal} onClick={e => e.stopPropagation()}>
        <div className={styles.header}>
          <h3 className={styles.title}>Cấu hình mã tham chiếu — Dòng #{row.rowIndex + 1}</h3>
          <button className={styles.closeBtn} onClick={onClose}>✕</button>
        </div>

        <div className={styles.infoBar}>
          {row.description && (
            <span><strong>Nội dung:</strong> {row.description}</span>
          )}
          {row.amount !== undefined && row.amount !== null && (
            <span><strong>Tiền:</strong> {row.amount.toLocaleString('vi-VN')}₫</span>
          )}
          {row.hasBatchDetail && (
            <span className={styles.hasDetailBadge}>✅ Có file sao kê chi tiết ({row.batchDetailLineCount || '?'} dòng)</span>
          )}
          {!row.hasBatchDetail && (
            <span className={styles.noDetailBadge}>⚠️ Không có sao kê chi tiết</span>
          )}
        </div>

        {/* Detected refs */}
        {detectedRefs.length > 0 && (
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Mã batch phát hiện từ nội dung:</label>
            <div className={styles.refList}>
              {detectedRefs.map((ref, i) => (
                <button
                  key={ref}
                  className={`${styles.refChip} ${!useManual && selectedRef === ref ? styles.refChipActive : ''}`}
                  onClick={() => {
                    setSelectedRef(ref);
                    setUseManual(false);
                  }}
                >
                  {ref}
                  {row.matchedBatchRefs?.includes(ref) && <span className={styles.matchedHint}>✓ có file</span>}
                </button>
              ))}
            </div>
          </div>
        )}

        {detectedRefs.length === 0 && (
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>Không phát hiện mã batch từ nội dung.</label>
          </div>
        )}

        {/* Manual ref input */}
        <div className={styles.fieldGroup}>
          <label className={styles.fieldLabel}>
            <input
              type="checkbox"
              checked={useManual}
              onChange={e => setUseManual(e.target.checked)}
            />{' '}
            Nhập mã tham chiếu thủ công
          </label>
          {useManual && (
            <input
              type="text"
              className={styles.textInput}
              value={manualRef}
              onChange={e => setManualRef(e.target.value)}
              placeholder="Nhập mã tham chiếu..."
            />
          )}
        </div>

        {/* Mark as batch transaction */}
        <div className={styles.fieldGroup}>
          <label className={styles.checkboxLabel}>
            <input
              type="checkbox"
              checked={isBatch}
              onChange={e => setIsBatch(e.target.checked)}
            />{' '}
            Đánh dấu là giao dịch batch
          </label>
          {isBatch && (
            <div className={styles.hint}>
              Giao dịch này là tổng hợp của nhiều giao dịch nhỏ theo mã batch.
            </div>
          )}
        </div>

        {/* Reason required when batch but no detail */}
        {isBatch && effectiveRef && !row.hasBatchDetail && (
          <div className={styles.fieldGroup}>
            <label className={styles.fieldLabel}>
              Lý do không có sao kê chi tiết <span className={styles.required}>*</span>
            </label>
            <textarea
              className={styles.textareaInput}
              value={reason}
              onChange={e => setReason(e.target.value)}
              placeholder="Vui lòng nhập lý do (VD: File lô không có sẵn, giao dịch tổng hợp từ ngân hàng...)"
              rows={3}
            />
            {!reason.trim() && (
              <div className={styles.warningText}>Vui lòng nhập lý do để confirm import.</div>
            )}
          </div>
        )}

        <div className={styles.actions}>
          <button className={styles.secondaryBtn} onClick={onClose}>Huỷ</button>
          <button
            className={styles.primaryBtn}
            onClick={handleSave}
            disabled={!!(isBatch && effectiveRef && !row.hasBatchDetail && !reason.trim())}
          >
            Xác nhận
          </button>
        </div>
      </div>
    </div>,
    document.body,
  );
};

export default BatchRefConfigModal;
