import React from 'react';
import type { BankStatementTemplateType } from '../../../../../services/kt/bankStatementImportModels';
import styles from './Step1Upload.module.css';

interface SelectedFileInfo {
  file: File;
  detectedTemplate: BankStatementTemplateType;
  rowCount: number;
  headers: string[];
}

interface Step1UploadProps {
  bankStatement: SelectedFileInfo | null;
  batchPayments: File[];
  skipEmptyRows: boolean;
  onSkipEmptyRowsChange: (skip: boolean) => void;
  onBankStatementSelect: (file: File) => void;
  onBatchPaymentAdd: (files: FileList) => void;
  onBatchPaymentRemove: (index: number) => void;
  onNext: () => void;
}

const TEMPLATE_LABEL: Record<BankStatementTemplateType, string> = {
  bao_no: 'Báo nợ',
  bao_co: 'Báo có',
  unc: 'Ủy nhiệm chi',
  ctnb: 'Chuyển tiền nội bộ',
};

const Step1Upload: React.FC<Step1UploadProps> = ({
  bankStatement,
  batchPayments,
  skipEmptyRows,
  onSkipEmptyRowsChange,
  onBankStatementSelect,
  onBatchPaymentAdd,
  onBatchPaymentRemove,
  onNext,
}) => {
  const handleBsDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const file = e.dataTransfer.files[0];
    if (file) onBankStatementSelect(file);
  };

  const handleBsInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) onBankStatementSelect(file);
  };

  const handleBatchDrop = (e: React.DragEvent) => {
    e.preventDefault();
    if (e.dataTransfer.files.length > 0) onBatchPaymentAdd(e.dataTransfer.files);
  };

  const handleBatchInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) onBatchPaymentAdd(e.target.files);
  };

  const canProceed = bankStatement !== null && bankStatement.rowCount > 0;

  return (
    <div className={styles.container}>
      <h2 className={styles.title}>Bước 1: Chọn file sao kê ngân hàng</h2>
      <p className={styles.subtitle}>
        Chọn file sao kê ngân hàng (master) và các file thanh toán lô (nếu có).
        Hỗ trợ .xlsx và .csv
      </p>

      {/* ── Bank statement file ─────────────────── */}
      <div className={styles.section}>
        <div className={styles.sectionTitle}>File sao kê ngân hàng</div>
        <div
          className={`${styles.dropZone} ${bankStatement ? styles.dropZoneFilled : ''}`}
          onDragOver={e => e.preventDefault()}
          onDrop={handleBsDrop}
        >
          {bankStatement ? (
            <div className={styles.fileCard}>
              <div className={styles.fileHeader}>
                <span className={styles.fileName}>{bankStatement.file.name}</span>
                <span className={styles.detectedBadge}>{TEMPLATE_LABEL[bankStatement.detectedTemplate]}</span>
              </div>
              <span className={styles.fileMeta}>
                {(bankStatement.file.size / 1024).toFixed(0)} KB &middot; {bankStatement.rowCount} dòng
              </span>
              <span className={styles.fileMeta}>
                {bankStatement.headers.length} cột: {bankStatement.headers.join(', ')}
              </span>
              <div className={styles.fileActions}>
                <label className={styles.changeLink}>
                  <input type="file" accept=".xlsx,.csv" hidden onChange={handleBsInput} />
                  Đổi file
                </label>
              </div>
            </div>
          ) : (
            <label className={styles.dropZoneInner}>
              <input type="file" accept=".xlsx,.csv" hidden onChange={handleBsInput} />
              <div className={styles.dropIcon}>📁</div>
              <div className={styles.dropLabel}>Chọn file sao kê</div>
              <div className={styles.dropHint}>Kéo thả hoặc nhấp để chọn .xlsx / .csv</div>
            </label>
          )}
        </div>
      </div>

      {/* ── Batch payment files ─────────────────── */}
      <div className={styles.section}>
        <div className={styles.sectionTitle}>File thanh toán lô</div>
        <div
          className={styles.batchZone}
          onDragOver={e => e.preventDefault()}
          onDrop={handleBatchDrop}
        >
          {batchPayments.length > 0 ? (
            <div className={styles.batchFileList}>
              {batchPayments.map((f, i) => (
                <div key={i} className={styles.batchFileItem}>
                  <span className={styles.batchFileName}>{f.name}</span>
                  <button
                    className={styles.batchFileRemove}
                    onClick={() => onBatchPaymentRemove(i)}
                    title="Xoá"
                  >
                    ✕
                  </button>
                </div>
              ))}
              <label className={styles.changeLink} style={{ marginTop: 8, textAlign: 'center', display: 'block' }}>
                <input type="file" accept=".xlsx,.csv" multiple hidden onChange={handleBatchInput} />
                + Thêm file thanh toán lô
              </label>
            </div>
          ) : (
            <label className={styles.dropZoneInner}>
              <input type="file" accept=".xlsx,.csv" multiple hidden onChange={handleBatchInput} />
              <div className={styles.dropIcon}>📄</div>
              <div className={styles.dropLabel}>Thêm file thanh toán lô</div>
              <div className={styles.dropHint}>Kéo thả hoặc nhấp. Có thể chọn nhiều file</div>
            </label>
          )}
        </div>
      </div>

      {/* ── Options ──────────────────────────────── */}
      <div className={styles.section}>
        <div className={styles.checkboxRow}>
          <input
            type="checkbox"
            id="skip-empty-rows"
            checked={skipEmptyRows}
            onChange={e => onSkipEmptyRowsChange(e.target.checked)}
          />
          <label htmlFor="skip-empty-rows">
            Bỏ qua các dòng trống (không có số tiền)
          </label>
        </div>
      </div>

      <div className={styles.actions}>
        <button className={styles.nextButton} disabled={!canProceed} onClick={onNext}>
          {canProceed
            ? `Tiếp theo: Xem trước & Phân tích (${bankStatement!.rowCount} dòng)`
            : 'Vui lòng chọn file sao kê'}
        </button>
      </div>
    </div>
  );
};

export default Step1Upload;
